#include <sys/types.h>
#include <sys/wait.h>
#include <iostream>

int main() {
    pid_t pid = fork();

    if (pid < 0) {
        std::cerr << "Fork failed" << std::endl;
        return 1;
    } else if (pid == 0) {
        // Child process
        close(0); // Close the old stdin
        close(1); // Close the old stdout

        // Redirect stdin and stdout to the same file
        int fd = open("yourfile.txt", O_RDWR);
        dup2(fd, 0); // Redirect stdin
        dup2(fd, 1); // Redirect stdout
        close(fd);

        execlp("/bin/cat", "cat", NULL); // Run cat on the file
    } else {
        // Parent process
        wait(NULL); // Wait for the child to finish
        std::cout << "Child process finished." << std::endl;
    }

    return 0;
}
```

This code sets up a new process where both the standard input and output are redirected to the same file. The child process runs the `cat` command on that file.

